def shuffle_options(ans_en, ans_kn, wrong_en, wrong_kn):
    comb = list(zip([ans_en] + wrong_en, [ans_kn] + wrong_kn))
    random.shuffle(comb)
    e, k = zip(*comb)
    return list(e), list(k)

def make_single(id_str, diff, q_en, q_kn, ans_en, ans_kn, wrong_en, wrong_kn, res_en, res_kn, img=None):
    e_opt, k_opt = shuffle_options(ans_en, ans_kn, wrong_en, wrong_kn)
    q = {
        "id": id_str, "type": "image_single" if img else "single", "difficulty": diff,
        "en": {"question": q_en, "options": e_opt, "answer": ans_en, "reasoning": res_en},
        "kn": {"question": q_kn, "options": k_opt, "answer": ans_kn, "reasoning": res_kn}
    }
    if img: q["image"] = img
    return q

def make_multi(id_str, diff, q_en, q_kn, ans_en, ans_kn, wrong_en, wrong_kn, res_en, res_kn, img=None):
    comb = list(zip(ans_en + wrong_en, ans_kn + wrong_kn))
    random.shuffle(comb)
    e_opt, k_opt = zip(*comb)
    q = {
        "id": id_str, "type": "image_multiple" if img else "multiple", "difficulty": diff,
        "en": {"question": q_en, "options": list(e_opt), "answer": ans_en, "reasoning": res_en},
        "kn": {"question": q_kn, "options": list(k_opt), "answer": ans_kn, "reasoning": res_kn}
    }
    if img: q["image"] = img
    return q

def make_match(id_str, diff, q_en, q_kn, pairs_en, pairs_kn, res_en, res_kn):
    return {
        "id": id_str, "type": "match", "difficulty": diff,
        "en": {"question": q_en, "pairs": [{"left": l, "right": r} for l, r in pairs_en], "reasoning": res_en},
        "kn": {"question": q_kn, "pairs": [{"left": l, "right": r} for l, r in pairs_kn], "reasoning": res_kn}
    }

def num_line_svg(start, end, points):
    svg = "<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 300 100'>"
    svg += "<line x1='20' y1='50' x2='280' y2='50' stroke='#2563EB' stroke-width='2'/>"
    step = 240 / (end - start)
    for i in range(start, end + 1):
        x = 30 + (i - start) * step
        svg += f"<line x1='{x}' y1='40' x2='{x}' y2='60' stroke='#2563EB' stroke-width='1.5'/>"
        svg += f"<text x='{x}' y='75' fill='#1F2937' font-family='Arial' font-size='12' text-anchor='middle'>{i}</text>"
    for p in points:
        val, col, lbl = p
        px = 30 + (val - start) * step
        svg += f"<circle cx='{px}' cy='50' r='6' fill='{col}'/>"
        if lbl:
            svg += f"<text x='{px}' y='30' fill='{col}' font-family='Arial' font-size='14' text-anchor='middle' font-weight='bold'>{lbl}</text>"
    svg += "</svg>"
    return {"type": "svg", "svg": svg, "alt": {"en": "Number line diagram", "kn": "ಸಂಖ್ಯಾ ರೇಖೆಯ ಚಿತ್ರ"}}

def geom_svg(shape, labels):
    if shape == "triangle":
        svg = "<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 300 200'>"
        svg += "<polygon points='150,30 50,150 250,150' fill='none' stroke='#2563EB' stroke-width='2'/>"
        svg += f"<text x='90' y='80' fill='#DC2626' font-family='Arial' font-size='14' text-anchor='middle' transform='rotate(-50, 90, 80)'>{labels.get('a','')}</text>"
        svg += f"<text x='210' y='80' fill='#DC2626' font-family='Arial' font-size='14' text-anchor='middle' transform='rotate(50, 210, 80)'>{labels.get('b','')}</text>"
        svg += f"<text x='150' y='170' fill='#DC2626' font-family='Arial' font-size='14' text-anchor='middle'>{labels.get('c','')}</text>"
        if labels.get('A'): svg += f"<text x='150' y='20' fill='#1F2937' font-family='Arial' font-size='14' text-anchor='middle'>{labels['A']}</text>"
        if labels.get('B'): svg += f"<text x='35' y='155' fill='#1F2937' font-family='Arial' font-size='14' text-anchor='middle'>{labels['B']}</text>"
        if labels.get('C'): svg += f"<text x='265' y='155' fill='#1F2937' font-family='Arial' font-size='14' text-anchor='middle'>{labels['C']}</text>"
        if labels.get('angleB'): 
            svg += "<path d='M70,150 A20,20 0 0,0 60,135' fill='none' stroke='#EA580C' stroke-width='1.5'/>"
            svg += f"<text x='85' y='145' fill='#EA580C' font-family='Arial' font-size='12'>{labels['angleB']}</text>"
        if labels.get('angleC'):
            svg += "<path d='M230,150 A20,20 0 0,1 240,135' fill='none' stroke='#EA580C' stroke-width='1.5'/>"
            svg += f"<text x='195' y='145' fill='#EA580C' font-family='Arial' font-size='12'>{labels['angleC']}</text>"
        if labels.get('angleA'):
            svg += "<path d='M140,45 A20,20 0 0,0 160,45' fill='none' stroke='#EA580C' stroke-width='1.5'/>"
            svg += f"<text x='150' y='65' fill='#EA580C' font-family='Arial' font-size='12' text-anchor='middle'>{labels['angleA']}</text>"
        svg += "</svg>"
        return {"type": "svg", "svg": svg, "alt": {"en": "Triangle diagram", "kn": "ತ್ರಿಕೋನದ ಚಿತ್ರ"}}
    elif shape == "rect":
        svg = "<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 300 200'>"
        svg += "<rect x='50' y='40' width='200' height='120' fill='none' stroke='#2563EB' stroke-width='2'/>"
        svg += f"<text x='150' y='30' fill='#DC2626' font-family='Arial' font-size='14' text-anchor='middle'>{labels.get('w','')}</text>"
        svg += f"<text x='270' y='100' fill='#DC2626' font-family='Arial' font-size='14' text-anchor='middle'>{labels.get('h','')}</text>"
        svg += "</svg>"
        return {"type": "svg", "svg": svg, "alt": {"en": "Rectangle diagram", "kn": "ಆಯತದ ಚಿತ್ರ"}}
    elif shape == "circle":
        svg = "<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 300 300'>"
        svg += "<circle cx='150' cy='150' r='100' fill='none' stroke='#2563EB' stroke-width='2'/>"
        svg += "<circle cx='150' cy='150' r='3' fill='#1F2937'/>"
        if labels.get('r'):
            svg += "<line x1='150' y1='150' x2='250' y2='150' stroke='#DC2626' stroke-width='1.5'/>"
            svg += f"<text x='200' y='140' fill='#DC2626' font-family='Arial' font-size='14' text-anchor='middle'>{labels['r']}</text>"
        if labels.get('d'):
            svg += "<line x1='50' y1='150' x2='250' y2='150' stroke='#DC2626' stroke-width='1.5'/>"
            svg += f"<text x='150' y='140' fill='#DC2626' font-family='Arial' font-size='14' text-anchor='middle'>{labels['d']}</text>"
        svg += "</svg>"
        return {"type": "svg", "svg": svg, "alt": {"en": "Circle diagram", "kn": "ವೃತ್ತದ ಚಿತ್ರ"}}

