qs2.append(make_single(f"c7_math_geom_{i2:03d}", 3, "In triangle ABC, AB = 5 cm, BC = 5 cm, and ∠B = 60°. What type of triangle is it?", "ತ್ರಿಕೋನ ABC ಯಲ್ಲಿ, AB = 5 ಸೆಂ.ಮೀ, BC = 5 ಸೆಂ.ಮೀ, ಮತ್ತು ∠B = 60°. ಇದು ಯಾವ ರೀತಿಯ ತ್ರಿಕೋನ?", "Equilateral", "ಸಮಬಾಹು ತ್ರಿಕೋನ", ["Isosceles but not equilateral", "Scalene", "Right-angled"], ["ಸಮದ್ವಿಬಾಹು ಆದರೆ ಸಮಬಾಹು ಅಲ್ಲ", "ಅಸಮಬಾಹು", "ಲಂಬಕೋನ ತ್ರಿಕೋನ"], "An isosceles triangle with a 60° angle between equal sides is equilateral.", "ಸಮಾನ ಬಾಹುಗಳ ನಡುವೆ 60° ಕೋನವನ್ನು ಹೊಂದಿರುವ ಸಮದ್ವಿಬಾಹು ತ್ರಿಕೋನವು ಸಮಬಾಹು ತ್ರಿಕೋನವಾಗಿರುತ್ತದೆ.")); i2+=1
qs2.append(make_single(f"c7_math_geom_{i2:03d}", 3, "Can we construct a unique triangle if only its three angles are given (e.g. 60°, 60°, 60°)?", "ಕೇವಲ ಅದರ ಮೂರು ಕೋನಗಳನ್ನು ನೀಡಿದ್ದರೆ (ಉದಾ. 60°, 60°, 60°) ನಾವು ಒಂದು ನಿರ್ದಿಷ್ಟ ತ್ರಿಕೋನವನ್ನು ರಚಿಸಬಹುದೇ?", "No, we can draw infinitely many of different sizes.", "ಇಲ್ಲ, ನಾವು ಬೇರೆ ಬೇರೆ ಗಾತ್ರದ ಅನಂತ ತ್ರಿಕೋನಗಳನ್ನು ರಚಿಸಬಹುದು.", ["Yes, exactly one unique triangle.", "No, such a triangle does not exist.", "Yes, if they are acute angles."], ["ಹೌದು, ನಿಖರವಾಗಿ ಒಂದೇ ತ್ರಿಕೋನ.", "ಇಲ್ಲ, ಅಂತಹ ತ್ರಿಕೋನ ಅಸ್ತಿತ್ವದಲ್ಲಿಲ್ಲ.", "ಹೌದು, ಅವು ಲಘುಕೋನಗಳಾಗಿದ್ದರೆ."], "AAA is not a congruence criterion; it only guarantees similar triangles.", "AAA ಸರ್ವಸಮತೆಯ ನಿಯಮವಲ್ಲ; ಅದು ಕೇವಲ ಸಮರೂಪ ತ್ರಿಕೋನಗಳನ್ನು ನೀಡುತ್ತದೆ.")); i2+=1
qs2.append(make_single(f"c7_math_geom_{i2:03d}", 3, "To construct triangle LMN with LM = 4 cm, ∠M = 100° and ∠N = 50°, we first need to find ∠L. What is it?", "LM = 4 ಸೆಂ.ಮೀ, ∠M = 100° ಮತ್ತು ∠N = 50° ಇರುವ LMN ತ್ರಿಕೋನವನ್ನು ರಚಿಸಲು, ನಾವು ಮೊದಲು ∠L ಅನ್ನು ಕಂಡುಹಿಡಿಯಬೇಕು. ಅದು ಎಷ್ಟು?", "30°", "30°", ["40°", "50°", "20°"], ["40°", "50°", "20°"], "180 - (100 + 50) = 30°.", "180 - (100 + 50) = 30°.")); i2+=1
qs2.append(make_single(f"c7_math_geom_{i2:03d}", 3, "In a right angled triangle PQR (right angled at Q), PR = 13 cm, QR = 5 cm. What is the length of PQ?", "ಲಂಬಕೋನ ತ್ರಿಕೋನ PQR ನಲ್ಲಿ (Q ನಲ್ಲಿ ಲಂಬಕೋನ), PR = 13 ಸೆಂ.ಮೀ, QR = 5 ಸೆಂ.ಮೀ. ಹಾಗಾದರೆ PQ ಉದ್ದ ಎಷ್ಟು?", "12 cm", "12 ಸೆಂ.ಮೀ.", ["8 cm", "144 cm", "10 cm"], ["8 ಸೆಂ.ಮೀ.", "144 ಸೆಂ.ಮೀ.", "10 ಸೆಂ.ಮೀ."], "Using Pythagoras theorem: PQ² = 13² - 5² = 169 - 25 = 144. PQ = 12.", "ಪೈಥಾಗರಸ್ ಪ್ರಮೇಯದ ಪ್ರಕಾರ: PQ² = 13² - 5² = 169 - 25 = 144. PQ = 12.")); i2+=1
qs2.append(make_single(f"c7_math_geom_{i2:03d}", 3, "Can you construct triangle XYZ if XY = 5 cm, YZ = 3 cm, and ZX = 8 cm?", "XY = 5 ಸೆಂ.ಮೀ, YZ = 3 ಸೆಂ.ಮೀ, ಮತ್ತು ZX = 8 ಸೆಂ.ಮೀ ಆಗಿದ್ದರೆ, ತ್ರಿಕೋನ XYZ ಅನ್ನು ರಚಿಸಲು ಸಾಧ್ಯವೇ?", "No, because sum of two sides equals the third.", "ಇಲ್ಲ, ಏಕೆಂದರೆ ಎರಡು ಬಾಹುಗಳ ಮೊತ್ತ ಮೂರನೇ ಬಾಹುವಿಗೆ ಸಮವಾಗಿದೆ.", ["Yes, by SSS criterion.", "No, because 8 cm is too long.", "Yes, it is a right-angled triangle."], ["ಹೌದು, SSS ನಿಯಮದ ಮೂಲಕ.", "ಇಲ್ಲ, ಏಕೆಂದರೆ 8 ಸೆಂ.ಮೀ ತುಂಬಾ ಉದ್ದವಾಗಿದೆ.", "ಹೌದು, ಇದು ಒಂದು ಲಂಬಕೋನ ತ್ರಿಕೋನ."], "5 + 3 = 8. The points will be collinear.", "5 + 3 = 8. ಬಿಂದುಗಳು ಏಕರೇಖಾಗತವಾಗಿರುತ್ತವೆ.")); i2+=1
qs2.append(make_single(f"c7_math_geom_{i2:03d}", 3, "While constructing a line parallel to a given line using compass and ruler, which geometric concept is primarily used?", "ಕೈವಾರ ಮತ್ತು ಅಳತೆಪಟ್ಟಿಯನ್ನು ಬಳಸಿ ದತ್ತ ರೇಖೆಗೆ ಸಮಾಂತರ ರೇಖೆಯನ್ನು ರಚಿಸುವಾಗ, ಯಾವ ರೇಖಾಗಣಿತದ ಪರಿಕಲ್ಪನೆಯನ್ನು ಮುಖ್ಯವಾಗಿ ಬಳಸಲಾಗುತ್ತದೆ?", "Copying an angle", "ಕೋನವನ್ನು ನಕಲಿಸುವುದು", ["Drawing a perpendicular bisector", "Finding the midpoint", "Trisecting an angle"], ["ಲಂಬ ವಿಭಾಜಕವನ್ನು ಎಳೆಯುವುದು", "ಮಧ್ಯಬಿಂದುವನ್ನು ಕಂಡುಹಿಡಿಯುವುದು", "ಕೋನವನ್ನು ತ್ರೈಭಾಜಿಸುವುದು"], "We copy an alternate interior angle to draw the parallel line.", "ಸಮಾಂತರ ರೇಖೆಯನ್ನು ಎಳೆಯಲು ನಾವು ಪರ್ಯಾಯ ಒಳಕೋನವನ್ನು ನಕಲಿಸುತ್ತೇವೆ.")); i2+=1

qs2.append(make_multi(f"c7_math_geom_{i2:03d}", 2, "Which sets of side lengths can form a triangle?", "ಯಾವ ಬಾಹುಗಳ ಉದ್ದಗಳ ಸೆಟ್‌ಗಳು ತ್ರಿಕೋನವನ್ನು ರೂಪಿಸಬಹುದು?", ["3, 4, 5", "5, 5, 5"], ["3, 4, 5", "5, 5, 5"], ["1, 2, 3", "2, 3, 6"], ["1, 2, 3", "2, 3, 6"], "The sum of any two sides must be strictly greater than the third side.", "ಯಾವುದೇ ಎರಡು ಬಾಹುಗಳ ಮೊತ್ತವು ಮೂರನೇ ಬಾಹುವಿಗಿಂತ ಕಡ್ಡಾಯವಾಗಿ ದೊಡ್ಡದಾಗಿರಬೇಕು.")); i2+=1
qs2.append(make_multi(f"c7_math_geom_{i2:03d}", 2, "Which sets of angles can form a triangle?", "ಯಾವ ಕೋನಗಳ ಸೆಟ್‌ಗಳು ತ್ರಿಕೋನವನ್ನು ರೂಪಿಸಬಹುದು?", ["60°, 60°, 60°", "90°, 45°, 45°"], ["60°, 60°, 60°", "90°, 45°, 45°"], ["90°, 90°, 10°", "50°, 50°, 50°"], ["90°, 90°, 10°", "50°, 50°, 50°"], "The sum of the three angles must be exactly 180°.", "ಮೂರು ಕೋನಗಳ ಮೊತ್ತವು ನಿಖರವಾಗಿ 180° ಆಗಿರಬೇಕು.")); i2+=1
qs2.append(make_multi(f"c7_math_geom_{i2:03d}", 2, "Which elements are required for the SAS criterion?", "SAS ನಿಯಮಕ್ಕೆ ಯಾವ ಅಂಶಗಳು ಬೇಕಾಗುತ್ತವೆ?", ["Two sides", "The included angle"], ["ಎರಡು ಬಾಹುಗಳು", "ಅವುಗಳ ನಡುವಿನ ಕೋನ"], ["Three sides", "A right angle"], ["ಮೂರು ಬಾಹುಗಳು", "ಒಂದು ಲಂಬಕೋನ"], "SAS means Side-Angle-Side (the angle must be between the two given sides).", "SAS ಎಂದರೆ ಬಾಹು-ಕೋನ-ಬಾಹು (ಕೋನವು ನೀಡಲಾದ ಎರಡು ಬಾಹುಗಳ ನಡುವೆ ಇರಬೇಕು).")); i2+=1
qs2.append(make_multi(f"c7_math_geom_{i2:03d}", 2, "Which of these are triangle congruence criteria?", "ಇವುಗಳಲ್ಲಿ ಯಾವುವು ತ್ರಿಕೋನ ಸರ್ವಸಮತೆಯ ನಿಯಮಗಳಾಗಿವೆ?", ["SSS", "SAS", "ASA", "RHS"], ["SSS", "SAS", "ASA", "RHS"], ["AAA", "SSA"], ["AAA", "SSA"], "AAA and SSA do not guarantee unique congruent triangles.", "AAA ಮತ್ತು SSA ಗಳು ನಿರ್ದಿಷ್ಟ ಸರ್ವಸಮ ತ್ರಿಕೋನಗಳನ್ನು ಖಾತರಿಪಡಿಸುವುದಿಲ್ಲ.")); i2+=1

qs2.append(make_match(f"c7_math_geom_{i2:03d}", 1, "Match the tool with its primary use in geometry.", "ಉಪಕರಣವನ್ನು ರೇಖಾಗಣಿತದಲ್ಲಿ ಅದರ ಪ್ರಾಥಮಿಕ ಉಪಯೋಗದೊಂದಿಗೆ ಹೊಂದಿಸಿ.", [("Compass", "Drawing arcs and circles"), ("Protractor", "Measuring angles"), ("Ruler", "Drawing straight lines"), ("Divider", "Comparing lengths")], [("ಕೈವಾರ (Compass)", "ಕಂಸಗಳು ಮತ್ತು ವೃತ್ತಗಳನ್ನು ಎಳೆಯುವುದು"), ("ಕೋನಮಾಪಕ (Protractor)", "ಕೋನಗಳನ್ನು ಅಳೆಯುವುದು"), ("ಅಳತೆಪಟ್ಟಿ (Ruler)", "ಸರಳ ರೇಖೆಗಳನ್ನು ಎಳೆಯುವುದು"), ("ವಿಭಾಜಕ (Divider)", "ಉದ್ದಗಳನ್ನು ಹೋಲಿಸುವುದು")], "Each tool has a specific purpose in construction.", "ಪ್ರತಿಯೊಂದು ಉಪಕರಣವು ರಚನೆಯಲ್ಲಿ ನಿರ್ದಿಷ್ಟ ಉದ್ದೇಶವನ್ನು ಹೊಂದಿದೆ.")); i2+=1
qs2.append(make_match(f"c7_math_geom_{i2:03d}", 2, "Match the construction criterion to its meaning.", "ರಚನೆಯ ನಿಯಮವನ್ನು ಅದರ ಅರ್ಥದೊಂದಿಗೆ ಹೊಂದಿಸಿ.", [("SSS", "Three sides given"), ("SAS", "Two sides and included angle"), ("ASA", "Two angles and included side"), ("RHS", "Right angle, hypotenuse, side")], [("SSS", "ಮೂರು ಬಾಹುಗಳನ್ನು ನೀಡಲಾಗಿದೆ"), ("SAS", "ಎರಡು ಬಾಹುಗಳು ಮತ್ತು ನಡುವಿನ ಕೋನ"), ("ASA", "ಎರಡು ಕೋನಗಳು ಮತ್ತು ನಡುವಿನ ಬಾಹು"), ("RHS", "ಲಂಬಕೋನ, ವಿಕರ್ಣ, ಬಾಹು")], "These are the standard criteria for triangle construction.", "ಇವು ತ್ರಿಕೋನ ರಚನೆಯ ಪ್ರಮಾಣಿತ ನಿಯಮಗಳಾಗಿವೆ.")); i2+=1
qs2.append(make_match(f"c7_math_geom_{i2:03d}", 2, "Match the triangle type to its property.", "ತ್ರಿಕೋನದ ಪ್ರಕಾರವನ್ನು ಅದರ ಗುಣಲಕ್ಷಣದೊಂದಿಗೆ ಹೊಂದಿಸಿ.", [("Equilateral", "All sides equal"), ("Isosceles", "Two sides equal"), ("Scalene", "No sides equal"), ("Right-angled", "One angle is 90 degrees")], [("ಸಮಬಾಹು", "ಎಲ್ಲಾ ಬಾಹುಗಳು ಸಮ"), ("ಸಮದ್ವಿಬಾಹು", "ಎರಡು ಬಾಹುಗಳು ಸಮ"), ("ಅಸಮಬಾಹು", "ಯಾವುದೇ ಬಾಹುಗಳು ಸಮನಾಗಿರುವುದಿಲ್ಲ"), ("ಲಂಬಕೋನ", "ಒಂದು ಕೋನ 90 ಡಿಗ್ರಿ")], "Triangles are classified by their sides and angles.", "ತ್ರಿಕೋನಗಳನ್ನು ಅವುಗಳ ಬಾಹುಗಳು ಮತ್ತು ಕೋನಗಳಿಂದ ವರ್ಗೀಕರಿಸಲಾಗುತ್ತದೆ.")); i2+=1
qs2.append(make_match(f"c7_math_geom_{i2:03d}", 3, "Match the given parts to the required criterion to construct it.", "ತ್ರಿಕೋನವನ್ನು ರಚಿಸಲು ನೀಡಲಾದ ಭಾಗಗಳನ್ನು ಅಗತ್ಯವಿರುವ ನಿಯಮದೊಂದಿಗೆ ಹೊಂದಿಸಿ.", [("AB=5, BC=6, AC=7", "SSS"), ("AB=5, ∠B=60°, BC=6", "SAS"), ("∠A=40°, AB=5, ∠B=50°", "ASA"), ("∠B=90°, AC=10, AB=6", "RHS")], [("AB=5, BC=6, AC=7", "SSS"), ("AB=5, ∠B=60°, BC=6", "SAS"), ("∠A=40°, AB=5, ∠B=50°", "ASA"), ("∠B=90°, AC=10, AB=6", "RHS")], "Identify which components (Side or Angle) are given.", "ಯಾವ ಘಟಕಗಳನ್ನು (ಬಾಹು ಅಥವಾ ಕೋನ) ನೀಡಲಾಗಿದೆ ಎಂಬುದನ್ನು ಗುರುತಿಸಿ.")); i2+=1
qs2.append(make_match(f"c7_math_geom_{i2:03d}", 3, "Match the third angle for a triangle given the first two.", "ಮೊದಲ ಎರಡು ಕೋನಗಳನ್ನು ನೀಡಿದಾಗ ತ್ರಿಕೋನದ ಮೂರನೇ ಕೋನವನ್ನು ಹೊಂದಿಸಿ.", [("50° and 60°", "70°"), ("90° and 45°", "45°"), ("110° and 30°", "40°"), ("60° and 60°", "60°")], [("50° ಮತ್ತು 60°", "70°"), ("90° ಮತ್ತು 45°", "45°"), ("110° ಮತ್ತು 30°", "40°"), ("60° ಮತ್ತು 60°", "60°")], "The sum of all three angles is always 180°.", "ಮೂರು ಕೋನಗಳ ಮೊತ್ತ ಯಾವಾಗಲೂ 180° ಆಗಿರುತ್ತದೆ.")); i2+=1

