qs3.append(make_single(f"c7_math_perim_{i3:03d}", 1, "What is the area of this rectangle?", "ಈ ಆಯತದ ವಿಸ್ತೀರ್ಣ ಎಷ್ಟು?", "12 cm²", "12 ಚ.ಸೆಂ.ಮೀ.", ["14 cm²", "7 cm²", "24 cm²"], ["14 ಚ.ಸೆಂ.ಮೀ.", "7 ಚ.ಸೆಂ.ಮೀ.", "24 ಚ.ಸೆಂ.ಮೀ."], "Area = length × width = 4 × 3 = 12.", "ವಿಸ್ತೀರ್ಣ = ಉದ್ದ × ಅಗಲ = 4 × 3 = 12.", geom_svg("rect", {"w": "4 cm", "h": "3 cm"}))); i3+=1
