qs3.append(make_single(f"c7_math_perim_{i3:03d}", 2, "If the radius of this circle is 7 cm, what is its circumference? (Use π = 22/7)", "ಈ ವೃತ್ತದ ತ್ರಿಜ್ಯ 7 ಸೆಂ.ಮೀ. ಆಗಿದ್ದರೆ, ಅದರ ಸುತ್ತಳತೆ ಎಷ್ಟು? (π = 22/7 ಬಳಸಿ)", "44 cm", "44 ಸೆಂ.ಮೀ.", ["22 cm", "154 cm", "14 cm"], ["22 ಸೆಂ.ಮೀ.", "154 ಸೆಂ.ಮೀ.", "14 ಸೆಂ.ಮೀ."], "C = 2πr = 2 * (22/7) * 7 = 44.", "C = 2πr = 2 * (22/7) * 7 = 44.", geom_svg("circle", {"r": "7 cm"}))); i3+=1
