qs3.append(make_multi(f"c7_math_perim_{i3:03d}", 3, "If a triangle has a base of 6 cm and height of 4 cm, which of these are true?", "ಒಂದು ತ್ರಿಕೋನದ ಪಾದ 6 ಸೆಂ.ಮೀ. ಮತ್ತು ಎತ್ತರ 4 ಸೆಂ.ಮೀ. ಆಗಿದ್ದರೆ, ಇವುಗಳಲ್ಲಿ ಯಾವುದು ಸರಿ?", ["Area is 12 cm²", "Area is (1/2)×6×4 cm²"], ["ವಿಸ್ತೀರ್ಣ 12 ಚ.ಸೆಂ.ಮೀ.", "ವಿಸ್ತೀರ್ಣ (1/2)×6×4 ಚ.ಸೆಂ.ಮೀ."], ["Area is 24 cm²", "Perimeter is 10 cm"], ["ವಿಸ್ತೀರ್ಣ 24 ಚ.ಸೆಂ.ಮೀ.", "ಸುತ್ತಳತೆ 10 ಸೆಂ.ಮೀ."], "Area of triangle = 1/2 × base × height.", "ತ್ರಿಕೋನದ ವಿಸ್ತೀರ್ಣ = 1/2 × ಪಾದ × ಎತ್ತರ.", geom_svg("triangle", {"c": "6 cm (Base)", "a": "Height=4"}))); i3+=1

qs3.append(make_single(f"c7_math_perim_{i3:03d}", 1, "The area of a square is 25 cm². What is its side length?", "ಒಂದು ಚೌಕದ ವಿಸ್ತೀರ್ಣ 25 ಚ.ಸೆಂ.ಮೀ. ಅದರ ಬಾಹುವಿನ ಉದ್ದವೆಷ್ಟು?", "5 cm", "5 ಸೆಂ.ಮೀ.", ["10 cm", "6.25 cm", "12.5 cm"], ["10 ಸೆಂ.ಮೀ.", "6.25 ಸೆಂ.ಮೀ.", "12.5 ಸೆಂ.ಮೀ."], "Area = side × side. 5 × 5 = 25.", "ವಿಸ್ತೀರ್ಣ = ಬಾಹು × ಬಾಹು. 5 × 5 = 25.")); i3+=1
