qs3.append(make_single(f"c7_math_perim_{i3:03d}", 1, "The distance around a circular region is known as its:", "ವೃತ್ತಾಕಾರದ ಪ್ರದೇಶದ ಸುತ್ತಲಿನ ಅಂತರವನ್ನು ಏನೆಂದು ಕರೆಯುತ್ತಾರೆ?", "Circumference", "ಪರಿಧಿ (Circumference)", ["Area", "Diameter", "Radius"], ["ವಿಸ್ತೀರ್ಣ", "ವ್ಯಾಸ", "ತ್ರಿಜ್ಯ"], "The boundary of a circle is its circumference.", "ವೃತ್ತದ ಗಡಿಯನ್ನು ಅದರ ಪರಿಧಿ ಎಂದು ಕರೆಯಲಾಗುತ್ತದೆ.")); i3+=1
qs3.append(make_single(f"c7_math_perim_{i3:03d}", 1, "If the diameter of a circle is 10 cm, what is its radius?", "ವೃತ್ತದ ವ್ಯಾಸ 10 ಸೆಂ.ಮೀ ಆಗಿದ್ದರೆ, ಅದರ ತ್ರಿಜ್ಯ ಎಷ್ಟು?", "5 cm", "5 ಸೆಂ.ಮೀ.", ["20 cm", "10 cm", "31.4 cm"], ["20 ಸೆಂ.ಮೀ.", "10 ಸೆಂ.ಮೀ.", "31.4 ಸೆಂ.ಮೀ."], "Radius = Diameter / 2.", "ತ್ರಿಜ್ಯ = ವ್ಯಾಸ / 2.")); i3+=1
qs3.append(make_single(f"c7_math_perim_{i3:03d}", 1, "What is the area of a triangle with base 10 cm and height 5 cm?", "10 ಸೆಂ.ಮೀ ಪಾದ ಮತ್ತು 5 ಸೆಂ.ಮೀ ಎತ್ತರವುಳ್ಳ ತ್ರಿಕೋನದ ವಿಸ್ತೀರ್ಣ ಎಷ್ಟು?", "25 cm²", "25 ಚ.ಸೆಂ.ಮೀ.", ["50 cm²", "15 cm²", "30 cm²"], ["50 ಚ.ಸೆಂ.ಮೀ.", "15 ಚ.ಸೆಂ.ಮೀ.", "30 ಚ.ಸೆಂ.ಮೀ."], "Area = 1/2 × base × height = 1/2 × 10 × 5 = 25.", "ವಿಸ್ತೀರ್ಣ = 1/2 × ಪಾದ × ಎತ್ತರ = 1/2 × 10 × 5 = 25.")); i3+=1
