qs3.append(make_single(f"c7_math_perim_{i3:03d}", 1, "Which unit is used to measure area?", "ವಿಸ್ತೀರ್ಣವನ್ನು ಅಳೆಯಲು ಯಾವ ಮಾನವನ್ನು ಬಳಸಲಾಗುತ್ತದೆ?", "Square meters (m²)", "ಚದರ ಮೀಟರ್ (m²)", ["Meters (m)", "Cubic meters (m³)", "Liters (L)"], ["ಮೀಟರ್ (m)", "ಘನ ಮೀಟರ್ (m³)", "ಲೀಟರ್ (L)"], "Area is measured in square units.", "ವಿಸ್ತೀರ್ಣವನ್ನು ಚದರ ಮಾನಗಳಲ್ಲಿ ಅಳೆಯಲಾಗುತ್ತದೆ.")); i3+=1
qs3.append(make_single(f"c7_math_perim_{i3:03d}", 1, "Value of π (pi) is approximately:", "π (ಪೈ) ನ ಅಂದಾಜು ಬೆಲೆ:", "22/7 or 3.14", "22/7 ಅಥವಾ 3.14", ["7/22 or 0.314", "3.41", "2.14"], ["7/22 ಅಥವಾ 0.314", "3.41", "2.14"], "Pi is approximately 22/7 or 3.14.", "ಪೈ ಬೆಲೆ ಸುಮಾರು 22/7 ಅಥವಾ 3.14 ಆಗಿದೆ.")); i3+=1

qs3.append(make_single(f"c7_math_perim_{i3:03d}", 2, "A rectangular garden is 30m long and 20m wide. What is the length of wire needed to fence it?", "ಒಂದು ಆಯತಾಕಾರದ ಉದ್ಯಾನವನ 30 ಮೀ ಉದ್ದ ಮತ್ತು 20 ಮೀ ಅಗಲವಿದೆ. ಅದಕ್ಕೆ ಬೇಲಿ ಹಾಕಲು ಬೇಕಾಗುವ ತಂತಿಯ ಉದ್ದ ಎಷ್ಟು?", "100 m", "100 ಮೀ.", ["600 m", "50 m", "120 m"], ["600 ಮೀ.", "50 ಮೀ.", "120 ಮೀ."], "Perimeter = 2(30 + 20) = 100.", "ಸುತ್ತಳತೆ = 2(30 + 20) = 100.")); i3+=1
qs3.append(make_single(f"c7_math_perim_{i3:03d}", 2, "If the circumference of a circle is 31.4 cm, find its radius. (Use π = 3.14)", "ವೃತ್ತದ ಪರಿಧಿ 31.4 ಸೆಂ.ಮೀ ಆಗಿದ್ದರೆ, ಅದರ ತ್ರಿಜ್ಯವನ್ನು ಕಂಡುಹಿಡಿಯಿರಿ. (π = 3.14 ಬಳಸಿ)", "5 cm", "5 ಸೆಂ.ಮೀ.", ["10 cm", "3.14 cm", "15.7 cm"], ["10 ಸೆಂ.ಮೀ.", "3.14 ಸೆಂ.ಮೀ.", "15.7 ಸೆಂ.ಮೀ."], "2 * 3.14 * r = 31.4 => 6.28r = 31.4 => r = 5.", "2 * 3.14 * r = 31.4 => 6.28r = 31.4 => r = 5.")); i3+=1
qs3.append(make_single(f"c7_math_perim_{i3:03d}", 2, "Find the area of a parallelogram with base 8 cm and height 4 cm.", "8 ಸೆಂ.ಮೀ ಪಾದ ಮತ್ತು 4 ಸೆಂ.ಮೀ ಎತ್ತರವಿರುವ ಸಮಾಂತರ ಚತುರ್ಭುಜದ ವಿಸ್ತೀರ್ಣವನ್ನು ಕಂಡುಹಿಡಿಯಿರಿ.", "32 cm²", "32 ಚ.ಸೆಂ.ಮೀ.", ["16 cm²", "24 cm²", "12 cm²"], ["16 ಚ.ಸೆಂ.ಮೀ.", "24 ಚ.ಸೆಂ.ಮೀ.", "12 ಚ.ಸೆಂ.ಮೀ."], "Area of parallelogram = base × height = 8 × 4 = 32.", "ಸಮಾಂತರ ಚತುರ್ಭುಜದ ವಿಸ್ತೀರ್ಣ = ಪಾದ × ಎತ್ತರ = 8 × 4 = 32.")); i3+=1
qs3.append(make_single(f"c7_math_perim_{i3:03d}", 2, "The area of a rectangular sheet is 500 cm². If the length is 25 cm, what is its width?", "ಒಂದು ಆಯತಾಕಾರದ ಹಾಳೆಯ ವಿಸ್ತೀರ್ಣ 500 ಚ.ಸೆಂ.ಮೀ. ಉದ್ದ 25 ಸೆಂ.ಮೀ ಆಗಿದ್ದರೆ, ಅದರ ಅಗಲ ಎಷ್ಟು?", "20 cm", "20 ಸೆಂ.ಮೀ.", ["25 cm", "10 cm", "50 cm"], ["25 ಸೆಂ.ಮೀ.", "10 ಸೆಂ.ಮೀ.", "50 ಸೆಂ.ಮೀ."], "Width = Area / Length = 500 / 25 = 20.", "ಅಗಲ = ವಿಸ್ತೀರ್ಣ / ಉದ್ದ = 500 / 25 = 20.")); i3+=1
qs3.append(make_single(f"c7_math_perim_{i3:03d}", 2, "What is the circumference of a circle of diameter 14 cm? (π = 22/7)", "14 ಸೆಂ.ಮೀ ವ್ಯಾಸವಿರುವ ವೃತ್ತದ ಪರಿಧಿ ಎಷ್ಟು? (π = 22/7)", "44 cm", "44 ಸೆಂ.ಮೀ.", ["22 cm", "88 cm", "154 cm"], ["22 ಸೆಂ.ಮೀ.", "88 ಸೆಂ.ಮೀ.", "154 ಸೆಂ.ಮೀ."], "C = π × d = (22/7) × 14 = 44.", "C = π × d = (22/7) × 14 = 44.")); i3+=1
qs3.append(make_single(f"c7_math_perim_{i3:03d}", 2, "1 hectare is equal to how many square meters?", "1 ಹೆಕ್ಟೇರ್ ಎಷ್ಟು ಚದರ ಮೀಟರ್‌ಗಳಿಗೆ ಸಮ?", "10,000 m²", "10,000 ಚ.ಮೀ.", ["1,000 m²", "100 m²", "100,000 m²"], ["1,000 ಚ.ಮೀ.", "100 ಚ.ಮೀ.", "100,000 ಚ.ಮೀ."], "1 hectare = 100m × 100m = 10,000 m².", "1 ಹೆಕ್ಟೇರ್ = 100ಮೀ × 100ಮೀ = 10,000 ಚ.ಮೀ.")); i3+=1

qs3.append(make_single(f"c7_math_perim_{i3:03d}", 3, "A square park has an area of 400 m². A path of width 2m is built inside its boundary. What is the side length of the inner square?", "ಒಂದು ಚೌಕಾಕಾರದ ಉದ್ಯಾನವನದ ವಿಸ್ತೀರ್ಣ 400 ಚ.ಮೀ. ಅದರ ಗಡಿಯೊಳಗೆ 2 ಮೀ. ಅಗಲದ ಹಾದಿಯನ್ನು ನಿರ್ಮಿಸಲಾಗಿದೆ. ಒಳಗಿನ ಚೌಕದ ಬಾಹುವಿನ ಉದ್ದವೆಷ್ಟು?", "16 m", "16 ಮೀ.", ["18 m", "20 m", "14 m"], ["18 ಮೀ.", "20 ಮೀ.", "14 ಮೀ."], "Outer side = 20m. Inner side = 20 - 2(2) = 16m.", "ಹೊರಗಿನ ಬಾಹು = 20ಮೀ. ಒಳಗಿನ ಬಾಹು = 20 - 2(2) = 16ಮೀ.")); i3+=1
qs3.append(make_single(f"c7_math_perim_{i3:03d}", 3, "The radius of a circular pipe is 10 cm. What length of tape is required to wrap once around the pipe? (π = 3.14)", "ವೃತ್ತಾಕಾರದ ಪೈಪ್‌ನ ತ್ರಿಜ್ಯ 10 ಸೆಂ.ಮೀ. ಪೈಪ್‌ನ ಸುತ್ತಲೂ ಒಮ್ಮೆ ಸುತ್ತಲು ಎಷ್ಟು ಉದ್ದದ ಟೇಪ್ ಬೇಕಾಗುತ್ತದೆ? (π = 3.14)", "62.8 cm", "62.8 ಸೆಂ.ಮೀ.", ["31.4 cm", "314 cm", "6.28 cm"], ["31.4 ಸೆಂ.ಮೀ.", "314 ಸೆಂ.ಮೀ.", "6.28 ಸೆಂ.ಮೀ."], "Length = Circumference = 2 × 3.14 × 10 = 62.8.", "ಉದ್ದ = ಪರಿಧಿ = 2 × 3.14 × 10 = 62.8.")); i3+=1
qs3.append(make_single(f"c7_math_perim_{i3:03d}", 3, "A wire is in the shape of a square of side 10 cm. If the wire is rebent into a rectangle of length 12 cm, find its breadth.", "ಒಂದು ತಂತಿಯು 10 ಸೆಂ.ಮೀ. ಬಾಹುವಿನ ಚೌಕದ ಆಕಾರದಲ್ಲಿದೆ. ಆ ತಂತಿಯನ್ನು 12 ಸೆಂ.ಮೀ. ಉದ್ದದ ಆಯತವಾಗಿ ಬಾಗಿಸಿದರೆ, ಅದರ ಅಗಲವನ್ನು ಕಂಡುಹಿಡಿಯಿರಿ.", "8 cm", "8 ಸೆಂ.ಮೀ.", ["6 cm", "10 cm", "12 cm"], ["6 ಸೆಂ.ಮೀ.", "10 ಸೆಂ.ಮೀ.", "12 ಸೆಂ.ಮೀ."], "Perimeter is same: 40 = 2(12 + b) => 20 = 12 + b => b = 8.", "ಸುತ್ತಳತೆ ಒಂದೇ: 40 = 2(12 + b) => 20 = 12 + b => b = 8.")); i3+=1
qs3.append(make_single(f"c7_math_perim_{i3:03d}", 3, "Find the area of a circle whose circumference is 31.4 cm (use π = 3.14).", "ವೃತ್ತದ ಪರಿಧಿ 31.4 ಸೆಂ.ಮೀ ಆಗಿದ್ದರೆ, ಅದರ ವಿಸ್ತೀರ್ಣವನ್ನು ಕಂಡುಹಿಡಿಯಿರಿ (π = 3.14 ಬಳಸಿ).", "78.5 cm²", "78.5 ಚ.ಸೆಂ.ಮೀ.", ["31.4 cm²", "100 cm²", "15.7 cm²"], ["31.4 ಚ.ಸೆಂ.ಮೀ.", "100 ಚ.ಸೆಂ.ಮೀ.", "15.7 ಚ.ಸೆಂ.ಮೀ."], "r = 31.4 / (2*3.14) = 5. Area = 3.14 * 5 * 5 = 78.5.", "r = 31.4 / (2*3.14) = 5. ವಿಸ್ತೀರ್ಣ = 3.14 * 5 * 5 = 78.5.")); i3+=1
qs3.append(make_single(f"c7_math_perim_{i3:03d}", 3, "A rectangular park is 45m long and 30m wide. A path 2.5m wide is constructed outside the park. Find the area of the path.", "ಒಂದು ಆಯತಾಕಾರದ ಉದ್ಯಾನವನ 45ಮೀ ಉದ್ದ ಮತ್ತು 30ಮೀ ಅಗಲವಿದೆ. ಉದ್ಯಾನವನದ ಹೊರಗೆ 2.5ಮೀ ಅಗಲದ ಹಾದಿಯನ್ನು ನಿರ್ಮಿಸಲಾಗಿದೆ. ಹಾದಿಯ ವಿಸ್ತೀರ್ಣವನ್ನು ಕಂಡುಹಿಡಿಯಿರಿ.", "400 m²", "400 ಚ.ಮೀ.", ["375 m²", "425 m²", "450 m²"], ["375 ಚ.ಮೀ.", "425 ಚ.ಮೀ.", "450 ಚ.ಮೀ."], "Outer = (45+5)×(30+5) = 50×35=1750. Inner = 45×30=1350. Path = 1750-1350 = 400.", "ಹೊರಗಿನದು = 50×35=1750. ಒಳಗಿನದು = 45×30=1350. ಹಾದಿ = 1750-1350 = 400.")); i3+=1
